diff --git a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
index ed93b4491c50..c0f0241b3b56 100644
--- a/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
+++ b/llvm/lib/Transforms/IPO/DeadArgumentElimination.cpp
@@ -89,6 +89,15 @@ public:

 bool isMustTailCalleeAnalyzable(const CallBase &CB) {
   assert(CB.isMustTailCall());
+  if (CB.getCaller()->getReturnType() != CB.getCalledFunction()->getReturnType()) {
+    LLVM_DEBUG(dbgs() << "Return type mismatch in musttail call: Caller: " << *CB.getCaller()->getReturnType() << ", Callee: " << *CB.getCalledFunction()->getReturnType() << "\n");
+    return false;
+  }
+  if (!isa<ReturnInst>(CB.getNextNode()) && !isa<BitCastInst>(CB.getNextNode())) {
+    LLVM_DEBUG(dbgs() << "Invalid instruction following musttail call: " << *CB.getNextNode() << "\n");
+    return false;
+  }
+  if (CB.getCaller()->getReturnType() != CB.getCalledFunction()->getReturnType()) return false;
   return CB.getCalledFunction() && !CB.getCalledFunction()->isDeclaration();
 }

